SELECT COUNT(*) AS total_registrations_2023
FROM vehicle_registration
WHERE year = 2023;

SELECT make_name, origin_country
FROM vehicle_make
WHERE make_id = 0;

SELECT license_plate, registration_status
FROM vehicle_registration
WHERE registration_status = 'Active';

SELECT COUNT(*) AS total_vehicles_registered
FROM registration_details
WHERE year = 2002;

SELECT registration_date, owner_name
FROM registration_details
WHERE year = 2002;
